use serde::Serialize;
#[derive(Serialize)]
enum Response {
    Loaded,
    Done { tokens: Vec<u32> },
    Error { message: String },
}
fn main() {
    let r1 = Response::Loaded;
    let r2 = Response::Done {
        tokens: vec![450, 8933],
    };
    let r3 = Response::Error {
        message: "hi".to_string(),
    };
    println!("Loaded: {:?}", bincode::serialize(&r1).unwrap());
    println!("Done: {:?}", bincode::serialize(&r2).unwrap());
    println!("Error: {:?}", bincode::serialize(&r3).unwrap());
}
